// src/credentials/ai-keys.ts
var SECRET_ID = "docker-agent-action/ai-api-keys";
var REGION = "us-east-1";
async function fetchAIApiKeys(credentials) {
  const client = new SecretsManagerClient({ region: REGION, credentials });
  let secretJson;
  try {
    const res = await client.send(new GetSecretValueCommand({ SecretId: SECRET_ID }));
    secretJson = res.SecretString ?? "";
  } catch (err) {
    warning(`AWS Secrets Manager unavailable, skipping ${SECRET_ID}: ${err}`);
    return;
  }
  setSecret(secretJson);
  let secret;
  try {
    secret = JSON.parse(secretJson);
  } catch {
    warning(`${SECRET_ID} did not return valid JSON; AI API keys will be empty`);
    return;
  }
  if (secret.anthropic_api_key) {
    setSecret(secret.anthropic_api_key);
    exportVariable("ANTHROPIC_API_KEY_FROM_SSM", secret.anthropic_api_key);
  }
  if (secret.openai_api_key) {
    setSecret(secret.openai_api_key);
    exportVariable("OPENAI_API_KEY_FROM_SSM", secret.openai_api_key);
  }
}

